+F2CSwaths& SingleCellSwathsOrderBase::genSortedSwaths() {
+  // Always sort swaths to work with them in the same direction.
+  swaths_.sort();
+  sortSwaths();
+  swaths_.reverseDirOddSwaths();
+  ++counter_;
+  return swaths_;
+}
