+void Cell::setGeometry(int i, const LinearRing& line) {
+  auto n = this->size();
+  if (i < n) {
+    auto* ref = this->getGeometry(i).get();
+    *ref = *line.get();
+    return;
+  } else if (i > n) {
+    for (int j = i; j < n; ++j) {
+      this->addGeometry(LinearRing());
+    }
+  }
+  this->addGeometry(line);
+}
