+  auto createRoute = [](const F2CSwaths& s) {
+    F2CRoute route;
+    route.connections.emplace_back(F2CMultiPoint());
+    route.connections.emplace_back(F2CMultiPoint());
+    route.v_swaths.emplace_back(s);
+    return route;
+  };
+    
