+TEST(fields2cover_types_multilinestring, append) {
+  F2CLinearRing ring1 {F2CPoint(0,0), F2CPoint(1,0), F2CPoint(1,1), F2CPoint(0,1), F2CPoint(0,0)};
+  F2CLinearRing ring2 = ring1.clone();
