+  const int n = 5;
+  F2CSwaths swaths;
+  for (int i = n - 1; i >= 1; --i) {
+    swaths.emplace_back(F2CLineString({F2CPoint(i, i), F2CPoint(i, i + 1)}), i, i);
+  }
+  auto rng = std::default_random_engine {};
+  std::shuffle(swaths.begin(), swaths.end(), rng);
+
+  swaths.sort();
+  for (int i = 1; i < n; ++i) {
