+  auto two_pi = boost::math::constants::two_pi<double>();
+  for (int i = 0; i < 10000; ++i) {
+    rand_val = rand.getAngleRandom();
+    EXPECT_LT( rand_val, two_pi);
+    EXPECT_GE( rand_val, 0.0);
+  }
+}
+
+TEST(fields2cover_utils_GeometryOp, get_random_double) {
+  f2c::Random rand;
